import org.springframework.context.annotation.*;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.boot.autoconfigure.jdbc.DataSourceProperties;
import com.zaxxer.hikari.HikariDataSource;
import javax.sql.DataSource;

@Configuration
public class MultiDataSourceConfig {

    // PAYMENTS DataSource (write-heavy: small pool, short connectionTimeout)
    @Bean @Primary
    @ConfigurationProperties("spring.datasource.payments")
    public DataSourceProperties paymentsProperties() { return new DataSourceProperties(); }

    @Bean @Primary @ConfigurationProperties("spring.datasource.payments.hikari")
    public DataSource paymentsDataSource() {
        return paymentsProperties().initializeDataSourceBuilder()
            .type(HikariDataSource.class)
            .build();
    }

    // ANALYTICS DataSource (read-heavy: larger pool, longer timeout OK)
    @Bean
    @ConfigurationProperties("spring.datasource.analytics")
    public DataSourceProperties analyticsProperties() { return new DataSourceProperties(); }

    @Bean @ConfigurationProperties("spring.datasource.analytics.hikari")
    public DataSource analyticsDataSource() {
        return analyticsProperties().initializeDataSourceBuilder()
            .type(HikariDataSource.class)
            .build();
    }
}

