import javax.sql.DataSource;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.sql.*;
import java.util.*;

@SpringBootTest
class PoolExhaustionTest {
    @Autowired DataSource dataSource;

    @Test
    void poolExhaustion_throwsAfterTimeout() throws SQLException {
        // Hold all connections (assuming pool size = 10 for test):
        List<Connection> held = new ArrayList<>();
        try {
            // Grab as many connections as available:
            for (int i = 0; i < 5; i++) {  // conservative: 5 of N
                try { held.add(dataSource.getConnection()); }
                catch (SQLException e) { break; }  // pool exhausted
            }

            // At this point: pool may be exhausted
            // Try to get another connection — should either succeed or timeout:
            long start = System.currentTimeMillis();
            try {
                Connection extra = dataSource.getConnection();
                held.add(extra);  // got one — pool wasn't fully exhausted
            } catch (SQLException e) {
                // ConnectionTimeout exception expected when pool exhausted:
                long elapsed = System.currentTimeMillis() - start;
                System.out.println("Connection timeout after: " + elapsed + "ms");
                assertTrue(elapsed < 5000, "Should timeout quickly (< 5s)");
                assertTrue(e.getMessage().contains("Unable to acquire") ||
                           e.getMessage().contains("timeout") ||
                           e instanceof java.sql.SQLTransientConnectionException);
            }
        } finally {
            // ALWAYS release connections:
            for (Connection c : held) { try { c.close(); } catch (Exception ignore) {} }
        }
    }
}

