import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest
class HikariMetricsTest {
    @Autowired MeterRegistry reg;

    @Test void hikariMetrics_areRegistered() {
        // HikariCP auto-registers metrics when MeterRegistry is in context:
        var activeGauge = reg.find("hikaricp.connections.active").gauge();
        var idleGauge   = reg.find("hikaricp.connections.idle").gauge();
        var maxGauge    = reg.find("hikaricp.connections.max").gauge();

        // At minimum: max connections gauge should be present:
        assertNotNull(maxGauge, "hikaricp.connections.max should be registered");
        // Idle + Active = Total connections created:
        System.out.println("Pool max: " + (maxGauge != null ? maxGauge.value() : "N/A"));
        System.out.println("Pool idle: " + (idleGauge != null ? idleGauge.value() : "N/A"));
        System.out.println("Pool active: " + (activeGauge != null ? activeGauge.value() : "N/A"));
    }

    @Test void hikariAcquireTimer_tracked() {
        // hikaricp.connections.acquire: Timer for time spent waiting for connection:
        var acquireTimers = reg.find("hikaricp.connections.acquire").timers();
        System.out.println("Acquire timers: " + acquireTimers.size());
        // May be 0 before any DB query in this test — that's OK
        assertNotNull(reg, "MeterRegistry should be wired");
    }
}

// PGBOUNCER OVERVIEW:

// WITHOUT PgBouncer:
// 10 payment-service instances × 20 HikariCP pool = 200 DB connections
// PostgreSQL max_connections = 200 → AT THE LIMIT
// Add 2 more service instances = 240 connections → EXCEEDS LIMIT → errors!

// WITH PgBouncer:
// App connects to PgBouncer (runs locally or on DB server)
// PgBouncer maintains a SMALL pool to PostgreSQL (e.g., 20 real DB connections)
// 10 services × 20 HikariCP → PgBouncer → 20 actual DB connections
// PgBouncer multiplexes: 200 app connections → 20 DB connections!

// PGBOUNCER MODES:
// 1. Session mode: one DB connection per client session (until client disconnects)
//    → Like having no pooler. Not useful for microservices.

// 2. Transaction mode (RECOMMENDED for Spring Boot):
//    DB connection held only for the duration of a TRANSACTION
//    Multiple app connections share same DB connection (when not in transaction)
//    LIMITATION: cannot use SET/RESET, advisory locks, server-side cursors
//    Compatibility: most Spring Data JPA operations work

// 3. Statement mode: one DB connection per SQL statement
//    Very aggressive — breaks multi-statement transactions
//    Not compatible with Spring JPA

// APPLICATION.YML for PgBouncer:
// spring.datasource.url: jdbc:postgresql://pgbouncer-host:6432/payments
//   (PgBouncer port: 6432 instead of PostgreSQL 5432)
// spring.datasource.hikari:
//   maximum-pool-size: 20   # HikariCP still pools → PgBouncer
//   connection-timeout: 5000  # slightly higher (PgBouncer adds latency)
//   # IMPORTANT for transaction mode:
// spring.jpa.properties.hibernate.connection.provider_disables_autocommit: true
//   # Tells Hibernate not to check autocommit (PgBouncer handles it)

public class PgBouncerGuide { public static void main(String[] a) {
    System.out.println("PgBouncer: 200 app connections → 20 DB connections"); } }

import org.springframework.boot.actuate.health.*;
import org.springframework.stereotype.Component;
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Component("hikariPool")
class HikariPoolHealthIndicator implements HealthIndicator {
    private final MeterRegistry reg;
    HikariPoolHealthIndicator(MeterRegistry r) { reg = r; }

    @Override public Health health() {
        Gauge active  = reg.find("hikaricp.connections.active").gauge();
        Gauge idle    = reg.find("hikaricp.connections.idle").gauge();
        Gauge pending = reg.find("hikaricp.connections.pending").gauge();
        Gauge max     = reg.find("hikaricp.connections.max").gauge();

        double pendingCount = pending != null ? pending.value() : 0;
        double activeCount  = active  != null ? active.value()  : 0;
        double idleCount    = idle    != null ? idle.value()    : 0;
        double maxCount     = max     != null ? max.value()     : 0;

        Health.Builder b = pendingCount > 5 ? Health.down() : Health.up();
        return b
            .withDetail("active",  activeCount)
            .withDetail("idle",    idleCount)
            .withDetail("pending", pendingCount)
            .withDetail("max",     maxCount)
            .build();
    }
}

@SpringBootTest
class HikariHealthTest {
    @Autowired HikariPoolHealthIndicator indicator;
    @Test void health_returnsDetails() {
        Health h = indicator.health();
        assertNotNull(h);
        assertNotNull(h.getDetails().get("max"));
        System.out.println("Pool health: " + h.getStatus() + " " + h.getDetails());
    }
}

import io.micrometer.core.instrument.*;
import org.springframework.boot.actuate.health.*;
