// application.yml (4-core SSD DB, 3 service instances):
// Formula: (4×2)+1 = 9 → 10 pool size
// spring.datasource.hikari:
//   maximum-pool-size: 10
//   minimum-idle: 3
//   connection-timeout: 3000
//   max-lifetime: 1800000
//   pool-name: RazorpayPool

@Service
class PoolMonitoringService {
    private final MeterRegistry reg;
    private final Counter timeouts;
    PoolMonitoringService(MeterRegistry r){
        reg=r;
        timeouts=Counter.builder("hikari.pool.timeouts").description("Connection timeout events").register(reg);
        Gauge.builder("hikari.pool.utilization",this,s->s.utilization()).register(reg);
    }
    double utilization(){
        Gauge a=reg.find("hikaricp.connections.active").gauge();
        Gauge m=reg.find("hikaricp.connections.max").gauge();
        return (a!=null&&m!=null&&m.value()>0)?a.value()/m.value():0.0;
    }
    void recordTimeout(){ timeouts.increment(); }
}

@Component("synth-hikari")
class SynthHikariHealth implements HealthIndicator {
    private final MeterRegistry reg;
    SynthHikariHealth(MeterRegistry r){reg=r;}
    @Override public Health health(){
        Gauge p=reg.find("hikaricp.connections.pending").gauge();
        double pending=p!=null?p.value():0;
        return (pending>5?Health.down():Health.up())
            .withDetail("pending",pending).build();
    }
}

@SpringBootTest
class M22T3SynthesisTest {
    @Autowired PoolMonitoringService svc;
    @Autowired SynthHikariHealth health;
    @Autowired MeterRegistry reg;
    @Test void gauge_registered(){
        assertNotNull(reg.find("hikari.pool.utilization").gauge());
        double u=svc.utilization();
        assertTrue(u>=0.0&&u<=1.0);
    }
    @Test void health_up_initially(){
        assertEquals(Status.UP, health.health().getStatus());
    }
}

