import javax.sql.DataSource;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.sql.*;

// application.yml:
// spring.datasource.hikari:
//   keepalive-time: 60000    # ping DB every 60s to prevent firewall timeout
//   connection-test-query: SELECT 1  # validation query
//   validation-timeout: 2000  # max ms for validation query
//   max-lifetime: 1800000    # 30 min: rotate before firewall kills at ~60 min
//   idle-timeout: 300000     # 5 min: remove idle connections (shorter than max-lifetime)

// WITHOUT KEEPALIVE (problem scenario):
// 8pm: all queries done for the night. Pool: 10 idle connections.
// Midnight: firewall kills TCP connections idle > 4 hours.
// 6am: trading starts. HikariCP tries to reuse connection → 'Connection reset'!
// Spring retries automatically (connectionTestQuery validates before use):
//   validation: SELECT 1 → SQLExcepton: broken pipe → remove from pool → get new connection
// With proper config: transparent to the application

// WITH KEEPALIVE:
// keepalive-time=60s: HikariCP sends SELECT 1 every 60s on idle connections
// Firewall sees periodic traffic → connection stays alive
// 6am: connections are all still valid → instant use

@SpringBootTest
class ConnectionValidityTest {
    @Autowired DataSource dataSource;

    @Test
    void dataSource_isReachable() throws SQLException {
        // Verify connection is valid:
        try (Connection conn = dataSource.getConnection();
             PreparedStatement stmt = conn.prepareStatement("SELECT 1")) {
            var rs = stmt.executeQuery();
            assertTrue(rs.next());
            assertEquals(1, rs.getInt(1));
        }
    }
}

